mapper.select:
SELECT b.id AS banId, b.user_id AS userId, u.nickname AS nickname, u.user_no AS userNo, b.ban_type AS banType, b.reason AS reason, b.ban_minutes AS banMinutes, b.expire_at AS expireAt, b.banned_by AS bannedBy, b.status AS status, b.created_at AS createdAt FROM im_user_ban b LEFT JOIN im_user u ON u.id = b.user_id
AND b.user_id = #{userId}
ORDER BY b.created_at DESC LIMIT #{offset}, #{pageSize}
